import React, { useState, useEffect } from "react";
import axios from "axios";
import { ResponsiveContainer, AreaChart, Area, YAxis } from "recharts";
import {
  Bitcoin,
  Coins,
  CircleDot,
  Database,
  Smartphone,
  XCircle
} from "lucide-react";

const COINS = [
  {
    id: "bitcoin",
    pair: "BTCTRY",
    name: "BITCOIN",
    symbol: "BTC",
    icon: Bitcoin,
    color: "#F7931A"
  },
  {
    id: "ethereum",
    pair: "ETHTRY",
    name: "ETHEREUM",
    symbol: "ETH",
    icon: Coins,
    color: "#627EEA"
  },
  {
    id: "solana",
    pair: "SOLTRY",
    name: "SOLANA",
    symbol: "SOL",
    icon: Smartphone,
    color: "#14F195"
  },
  {
    id: "binancecoin",
    pair: "BNBTRY",
    name: "BINANCE COIN",
    symbol: "BNB",
    icon: CircleDot,
    color: "#F3BA2F"
  },
  {
    id: "cardano",
    pair: "ADATRY",
    name: "CARDANO",
    symbol: "ADA",
    icon: Database,
    color: "#0033AD"
  },
  {
    id: "ripple",
    pair: "XRPTRY",
    name: "XRP",
    symbol: "XRP",
    icon: XCircle,
    color: "#ffffff"
  }
];

const CryptoBox = ({ coin }) => {
  const Icon = coin.icon;
  const isPositive = coin.change >= 0;

  return (
    <div className="crypto-item-box">
      <div className="coin-left-section">
        <div
          className="coin-icon-wrapper"
          style={{
            background: `linear-gradient(135deg, ${coin.color}33, ${coin.color}11)`
          }}
        >
          <Icon size={28} color={coin.color} />
        </div>

        <div className="coin-details">
          <h3 className="coin-title">
            {coin.name} ({coin.symbol})
          </h3>

          <div className="price-info">
            <span className="coin-price">
              {coin.price.toLocaleString("tr-TR")} ₺
            </span>

            <span className={`coin-change ${isPositive ? "up" : "down"}`}>
              {isPositive ? "+" : ""}
              {coin.change.toFixed(2)}%
            </span>
          </div>
        </div>
      </div>

      <div className="coin-right-section">
        <ResponsiveContainer width="100%" height={60}>
          <AreaChart data={coin.history}>
            <YAxis hide domain={["dataMin", "dataMax"]} />

            <Area
              type="monotone"
              dataKey="price"
              stroke={coin.color}
              fill={coin.color}
              fillOpacity={0.2}
              strokeWidth={2}
              dot={false}
            />
          </AreaChart>
        </ResponsiveContainer>
      </div>
    </div>
  );
};

export default function FinanceCoin() {
  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(true);

  const fetchData = async () => {
    try {
      const coinsData = await Promise.all(
        COINS.map(async (coin) => {
          const res = await axios.get(
            `https://api.coingecko.com/api/v3/coins/${coin.id}/market_chart?vs_currency=try&days=1`
          );

          const prices = res.data.prices;

          const history = prices.map((p) => ({
            price: p[1]
          }));

          const first = prices[0][1];
          const last = prices[prices.length - 1][1];

          const change = ((last - first) / first) * 100;

          return {
            ...coin,
            price: last,
            change,
            history
          };
        })
      );

      setData(coinsData);
      setLoading(false);
    } catch (err) {
      console.error(err);
    }
  };

  useEffect(() => {
    fetchData();
    const interval = setInterval(fetchData, 30000);
    return () => clearInterval(interval);
  }, []);

  if (loading) return <div>Veriler Yükleniyor...</div>;

  return (
    <div className="market-insight-wrapper">
      <div className="market-header">
        <h2 className="market-main-title">CRYPTO MARKET INSIGHTS</h2>
        <div className="live-indicator">
          <span>●</span> CANLI
        </div>
      </div>

      <div className="crypto-boxes-container">
        {data.map((coin) => (
          <CryptoBox key={coin.symbol} coin={coin} />
        ))}
      </div>
    </div>
  );
}
